import { test, expect } from '@playwright/test'
import { searchWith, waitForResults, getResultCount } from './helpers'

// ── Critical ────────────────────────────────────────────────────────────────

test.describe('Navigation & Deep Links — Critical', () => {
  test('navigate directly to /search?state=CA pre-populates state filter with matching results @critical @nav', async ({
    page,
  }) => {
    await searchWith(page, { state: 'CA' })
    await waitForResults(page)

    // The state select should have CA selected
    const stateSelect = page.locator('label', { has: page.getByText('State') }).locator('select')
    await expect(stateSelect).toHaveValue('CA')

    // Results should be showing
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)
  })
})

// ── Standard ────────────────────────────────────────────────────────────────

test.describe('Navigation — Standard', () => {
  test('header nav: Home → About → Home works via nav links @standard @nav', async ({ page }) => {
    await page.goto('/')

    // Verify we are on the home page
    await expect(
      page.getByRole('heading', { name: 'College Power Search', level: 1 }),
    ).toBeVisible()

    // Click About link in desktop nav
    await page.getByRole('link', { name: 'About' }).click()

    // Verify we navigated to the About page
    await expect(page).toHaveURL('/about')
    await expect(page.getByRole('heading', { name: /About College Power Search/i })).toBeVisible()

    // Click Home link in desktop nav
    await page.getByRole('link', { name: 'Home' }).click()

    // Verify we are back on the home page
    await expect(page).toHaveURL('/')
    await expect(
      page.getByRole('heading', { name: 'College Power Search', level: 1 }),
    ).toBeVisible()
  })

  test('logo click returns to home from any page @standard @nav', async ({ page }) => {
    // Start on the About page
    await page.goto('/about')
    await expect(page.getByRole('heading', { name: /About College Power Search/i })).toBeVisible()

    // Click the logo/wordmark link (links to "/", contains "College Power Search" text)
    const logoLink = page.locator('header a[href="/"]').filter({ hasText: 'College Power Search' })
    await logoLink.click()

    // Verify we navigated back to home
    await expect(page).toHaveURL('/')
    await expect(
      page.getByRole('heading', { name: 'College Power Search', level: 1 }),
    ).toBeVisible()
  })

  test('mobile viewport: hamburger menu appears, desktop nav hidden @standard @responsive', async ({
    page,
  }) => {
    // Set mobile viewport (375px wide)
    await page.setViewportSize({ width: 375, height: 812 })
    await page.goto('/')

    // Desktop nav links should be hidden at this viewport
    // The desktop nav uses visibleFrom="md" which means hidden below 768px
    const desktopHomeLink = page.locator('header').getByRole('link', { name: 'Home' })
    // On mobile the Home/About links inside visibleFrom="md" Group are hidden
    // The burger button should be visible
    const burger = page.getByRole('button', { name: 'Toggle navigation' })
    await expect(burger).toBeVisible()

    // Click burger to open the navigation drawer
    await burger.click()

    // The drawer should contain Home and About links
    const drawer = page.locator('[role="dialog"]').filter({ hasText: 'Navigation' })
    await expect(drawer).toBeVisible()
    await expect(drawer.getByRole('link', { name: 'Home' })).toBeVisible()
    await expect(drawer.getByRole('link', { name: 'About' })).toBeVisible()

    // Verify desktop nav links are not visible in the header (not inside drawer)
    // The visibleFrom="md" Group is hidden at 375px
    await expect(desktopHomeLink).toBeHidden()
  })
})

// ── Comprehensive ───────────────────────────────────────────────────────────

test.describe('Responsive & Deep Links — Comprehensive', () => {
  test('mobile: Show/Hide Filters toggle works on search page @comprehensive @responsive', async ({
    page,
  }) => {
    // Set mobile viewport
    await page.setViewportSize({ width: 375, height: 812 })

    await searchWith(page, {})
    await waitForResults(page)

    // On mobile, the filter sidebar is collapsed by default
    // A "Show Filters" button should be visible
    const toggleButton = page.getByRole('button', { name: /Show Filters|Hide Filters/i })
    await expect(toggleButton).toBeVisible()
    await expect(toggleButton).toHaveText('Show Filters')

    // The "Filters" heading should not be visible (collapsed)
    await expect(page.getByText('Filters', { exact: true }).locator('visible=true').first()).toBeHidden()

    // Click to show filters
    await toggleButton.click()
    await expect(toggleButton).toHaveText('Hide Filters')

    // Filter content should now be visible — the "Filters" title heading appears
    await expect(page.locator('main').getByText('Filters', { exact: true }).first()).toBeVisible()

    // Click to hide filters again
    await toggleButton.click()
    await expect(toggleButton).toHaveText('Show Filters')
  })

  test('tablet viewport: layout adapts with collapsible filters above results @comprehensive @responsive', async ({
    page,
  }) => {
    // Set tablet viewport (768px — exactly at the md breakpoint)
    // Mantine md = 62em ≈ 992px. At 768px, the layout should be column (mobile-style).
    await page.setViewportSize({ width: 768, height: 1024 })

    await searchWith(page, {})
    await waitForResults(page)

    // At 768px (below Mantine md = 62em = 992px), the filter toggle button should appear
    // because isDesktop = useMediaQuery('(min-width: 62em)') will be false
    const toggleButton = page.getByRole('button', { name: /Show Filters|Hide Filters/i })
    await expect(toggleButton).toBeVisible()

    // Results heading should be visible below the filter area
    await expect(page.getByRole('heading', { name: 'Results' })).toBeVisible()

    // The layout should be vertical (column direction) — filters above results
    // Verify both are in the page and visible
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)
  })

  test('all filters round-trip through URL: set filters → copy URL → navigate → same state and results @comprehensive @nav', async ({
    page,
  }) => {
    // Navigate to search and apply multiple filters via URL
    await searchWith(page, { state: 'NY', enrollment: '1000,10000' })
    await waitForResults(page)
    const countFirst = await getResultCount(page)
    expect(countFirst).toBeGreaterThan(0)

    // Capture the current URL
    const url = page.url()

    // Verify URL contains both filter params
    expect(url).toMatch(/[?&]state=NY/)
    expect(url).toMatch(/[?&]enrollment=1000,10000/)

    // Navigate away to home
    await page.goto('/')
    await expect(
      page.getByRole('heading', { name: 'College Power Search', level: 1 }),
    ).toBeVisible()

    // Navigate back to the captured URL
    await page.goto(url)
    await waitForResults(page)

    // Verify filter state is restored — state select should show NY
    const stateSelect = page.locator('label', { has: page.getByText('State') }).locator('select')
    await expect(stateSelect).toHaveValue('NY')

    // Result count should match
    const countSecond = await getResultCount(page)
    expect(countSecond).toBe(countFirst)
  })
})

